package com.copilotkit.showcase.springai.tools;

import com.fasterxml.jackson.databind.ObjectMapper;
import org.springframework.web.client.RestClientException;
import org.springframework.web.client.RestTemplate;
import org.springframework.web.util.UriComponentsBuilder;

import java.util.HashMap;
import java.util.Map;
import java.util.function.Function;

/**
 * Server-side weather tool that calls the Open-Meteo API.
 * Registered as "get_weather" in AgentConfig.
 */
public class WeatherTool implements Function<WeatherRequest, String> {

    private static final Map<Integer, String> CONDITIONS = new HashMap<>();
    static {
        CONDITIONS.put(0, "Clear sky");
        CONDITIONS.put(1, "Mainly clear");
        CONDITIONS.put(2, "Partly cloudy");
        CONDITIONS.put(3, "Overcast");
        CONDITIONS.put(51, "Light drizzle");
        CONDITIONS.put(61, "Slight rain");
        CONDITIONS.put(63, "Moderate rain");
        CONDITIONS.put(65, "Heavy rain");
        CONDITIONS.put(71, "Slight snow");
        CONDITIONS.put(80, "Rain showers");
        CONDITIONS.put(95, "Thunderstorm");
    }

    private final RestTemplate restTemplate = new RestTemplate();

    @Override
    public String apply(WeatherRequest request) {
        WeatherResponse.GeocodingResponse geo;
        try {
            // Geocode the location
            String geoUrl = UriComponentsBuilder
                    .fromHttpUrl("https://geocoding-api.open-meteo.com/v1/search")
                    .queryParam("name", request.getLocation())
                    .queryParam("count", 1)
                    .toUriString();

            geo = restTemplate.getForObject(geoUrl, WeatherResponse.GeocodingResponse.class);
        } catch (RestClientException e) {
            return "Failed to geocode location '" + request.getLocation() + "': " + e.getMessage();
        }

        if (geo == null || geo.getResults() == null || geo.getResults().isEmpty()) {
            return "Location not found: " + request.getLocation();
        }

        WeatherResponse.GeocodingResult loc = geo.getResults().get(0);

        WeatherResponse weather;
        try {
            // Get weather
            String weatherUrl = UriComponentsBuilder
                    .fromHttpUrl("https://api.open-meteo.com/v1/forecast")
                    .queryParam("latitude", loc.getLatitude())
                    .queryParam("longitude", loc.getLongitude())
                    .queryParam("current", "temperature_2m,apparent_temperature,relative_humidity_2m,wind_speed_10m,weather_code")
                    .toUriString();

            weather = restTemplate.getForObject(weatherUrl, WeatherResponse.class);
        } catch (RestClientException e) {
            return "Failed to fetch weather for " + loc.getName() + ": " + e.getMessage();
        }

        if (weather == null || weather.getCurrent() == null) {
            return "Could not fetch weather for " + loc.getName();
        }

        WeatherResponse.CurrentWeather w = weather.getCurrent();
        String conditions = CONDITIONS.getOrDefault(w.getWeatherCode(), "Unknown");

        try {
            return new ObjectMapper().writeValueAsString(Map.of(
                    "city", loc.getName(),
                    "temperature", w.getTemperature2m(),
                    "humidity", (int) w.getRelativeHumidity2m(),
                    "wind_speed", w.getWindSpeed10m(),
                    "feels_like", w.getApparentTemperature(),
                    "conditions", conditions
            ));
        } catch (Exception e) {
            return "{\"error\": \"Failed to serialize weather data: " + e.getMessage() + "\"}";
        }
    }
}

/**
 * Demonstration Catalog -- Component Definitions
 *
 * Platform-agnostic definitions: component names, props (Zod), descriptions.
 * This is the contract between the app and the AI agent. Agents receive these
 * definitions as context so they know what components are available.
 *
 * Renderers (React, React Native, etc.) import these definitions and provide
 * platform-specific implementations, type-checked against the Zod schemas.
 */

import { z } from "zod";

/**
 * Dynamic string: accepts either a literal string or a data-model path binding
 * like `{ path: "airline" }`. The GenericBinder resolves path bindings to the
 * actual value at render time.
 */
const DynString = z.union([z.string(), z.object({ path: z.string() })]);

/**
 * Shared action schema used by interactive components (Button, FlightCard).
 * The GenericBinder resolves `{ event }` objects to callable `() => void` at
 * render time.
 */
const ActionSchema = z
  .union([
    z.object({
      event: z.object({
        name: z.string(),
        context: z.record(z.any()).optional(),
      }),
    }),
    z.null(),
  ])
  .optional();

export const demonstrationCatalogDefinitions = {
  Title: {
    description: "A heading. Use for section titles and page headers.",
    props: z.object({
      text: z.string(),
      level: z.string().optional(),
    }),
  },

  // Text: removed -- the basic catalog's Text uses DynamicStringSchema
  // which supports path bindings (e.g. { path: "flights[*].airline" }).
  // Overriding it with z.string() breaks fixed-schema data binding.

  Row: {
    description: "Horizontal layout container.",
    props: z.object({
      gap: z.number().optional(),
      align: z.string().optional(),
      justify: z.string().optional(),
      // Union with { componentId, path } so GenericBinder treats this as
      // STRUCTURAL and resolves template children from the data model.
      children: z.union([
        z.array(z.string()),
        z.object({ componentId: z.string(), path: z.string() }),
      ]),
    }),
  },

  Column: {
    description: "Vertical layout container.",
    props: z.object({
      gap: z.number().optional(),
      align: z.string().optional(),
      // Same union as Row -- required for template children support.
      children: z.union([
        z.array(z.string()),
        z.object({ componentId: z.string(), path: z.string() }),
      ]),
    }),
  },

  DashboardCard: {
    description:
      "A card container with title and optional subtitle. Has a 'child' slot for content (chart, metrics, etc). Use 'child' with a single component ID.",
    props: z.object({
      title: z.string(),
      subtitle: z.string().optional(),
      child: z.string().optional(),
    }),
  },

  Metric: {
    description:
      "A key metric display with label, value, and optional trend indicator. Great for KPIs and stats.",
    props: z.object({
      label: z.string(),
      value: z.string(),
      trend: z.enum(["up", "down", "neutral"]).optional(),
      trendValue: z.string().optional(),
    }),
  },

  PieChart: {
    description:
      "A pie/donut chart. Provide data as array of {label, value, color} objects.",
    props: z.object({
      data: z.array(
        z.object({
          label: z.string(),
          value: z.number(),
          color: z.string().optional(),
        }),
      ),
      innerRadius: z.number().optional(),
    }),
  },

  BarChart: {
    description:
      "A bar chart. Provide data as array of {label, value} objects.",
    props: z.object({
      data: z.array(z.object({ label: z.string(), value: z.number() })),
      color: z.string().optional(),
    }),
  },

  Badge: {
    description:
      "A small status badge/tag. Use for labels, statuses, categories.",
    props: z.object({
      text: z.string(),
      variant: z
        .enum(["success", "warning", "error", "info", "neutral"])
        .optional(),
    }),
  },

  DataTable: {
    description: "A data table with columns and rows.",
    props: z.object({
      columns: z.array(z.object({ key: z.string(), label: z.string() })),
      rows: z.array(z.record(z.any())),
    }),
  },

  Button: {
    description:
      "An interactive button with an action event. Use 'child' with a Text component ID for the label. 'action' is dispatched on click.",
    props: z.object({
      child: z
        .string()
        .describe(
          "The ID of the child component (e.g. a Text component for the label).",
        ),
      variant: z.enum(["primary", "secondary", "ghost"]).optional(),
      action: ActionSchema,
    }),
  },

  FlightCard: {
    description:
      "A rich flight result card. Displays airline, flight number, route, times, duration, status, and price. Use inside a Row for side-by-side layout.",
    props: z.object({
      airline: DynString,
      airlineLogo: DynString,
      flightNumber: DynString,
      origin: DynString,
      destination: DynString,
      date: DynString,
      departureTime: DynString,
      arrivalTime: DynString,
      duration: DynString,
      status: DynString,
      statusColor: DynString.optional(),
      price: DynString,
      action: ActionSchema,
    }),
  },
};

